    {"id": 16, "number": 16, "category": "الغضب", "narrator": "أبو هريرة رضي الله عنه", "source": "البخاري",
     "arabic": "لَا تَغْضَبْ. فَرَدَّدَ مِرَارًا، قَالَ: لَا تَغْضَبْ",
     "full_arabic": "عن أبي هريرة رضي الله عنه أن رجلاً قال للنبي صلى الله عليه وسلم: أوصني. قال: «لَا تَغْضَبْ». فَرَدَّدَ مِرَارًا، قَالَ: «لَا تَغْضَبْ»",
     "translation": "لا تغضب"},

    {"id": 17, "number": 17, "category": "الإحسان", "narrator": "أبو يعلى شداد بن أوس رضي الله عنه", "source": "الترمذي",
     "arabic": "إِنَّ اللهَ كَتَبَ الإِحْسَانَ عَلَى كُلِّ شَيْءٍ",
     "full_arabic": "عن أبي يعلى شداد بن أوس رضي الله عنه عن رسول الله صلى الله عليه وسلم قال: «إِنَّ اللهَ كَتَبَ الإِحْسَانَ عَلَى كُلِّ شَيْءٍ، فَإِذَا قَتَلْتُمْ فَأَحْسِنُوا الْقِتْلَةَ، وَإِذَا ذَبَحْتُمْ فَأَحْسِنُوا الذَّبْحَ، وَلْيُحِدَّ أَحَدُكُمْ شَفْرَتَهُ وَلْيُرِحْ ذَبِيحَتَهُ»",
     "translation": "إن الله كتب الإحسان على كل شيء"},

    {"id": 18, "number": 18, "category": "التقوى", "narrator": "أبو ذر الغفاري رضي الله عنه", "source": "الترمذي",
     "arabic": "اتَّقِ اللهَ حَيْثُمَا كُنْتَ، وَأَتْبِعِ السَّيِّئَةَ الْحَسَنَةَ تَمْحُهَا، وَخَالِقِ النَّاسَ بِخُلُقٍ حَسَنٍ",
     "full_arabic": "عن أبي ذر جندب بن جنادة رضي الله عنه قال: قال رسول الله صلى الله عليه وسلم: «اتَّقِ اللهَ حَيْثُمَا كُنْتَ، وَأَتْبِعِ السَّيِّئَةَ الْحَسَنَةَ تَمْحُهَا، وَخَالِقِ النَّاسَ بِخُلُقٍ حَسَنٍ»",
     "translation": "اتق الله حيثما كنت، وأتبع السيئة الحسنة تمحها، وخالق الناس بخلق حسن"},

    {"id": 19, "number": 19, "category": "تقوى الله", "narrator": "ابن عباس رضي الله عنهما", "source": "الترمذي",
     "arabic": "يَا غُلَامُ، إِنِّي أُعَلِّمُكَ كَلِمَاتٍ: احْفَظِ اللهَ يَحْفَظْكَ، احْفَظِ اللهَ تَجِدْهُ تُجَاهَكَ",
     "full_arabic": "عن ابن عباس رضي الله عنهما قال: كنت خلف النبي صلى الله عليه وسلم يوماً فقال: «يَا غُلَامُ، إِنِّي أُعَلِّمُكَ كَلِمَاتٍ: احْفَظِ اللهَ يَحْفَظْكَ، احْفَظِ اللهَ تَجِدْهُ تُجَاهَكَ، إِذَا سَأَلْتَ فَاسْأَلِ اللهَ، وَإِذَا اسْتَعَنْتَ فَاسْتَعِنْ بِاللهِ»",
     "translation": "يا غلام، إني أعلمك كلمات: احفظ الله يحفظك، احفظ الله تجده تجاهك"},

    {"id": 20, "number": 20, "category": "الحياء", "narrator": "أبو مسعود عقبة بن عمرو البدري رضي الله عنه", "source": "متفق عليه",
     "arabic": "إِنَّ مِمَّا أَدْرَكَ النَّاسُ مِنْ كَلَامِ النُّبُوَّةِ الْأُولَى: إِذَا لَمْ تَسْتَحِ فَاصْنَعْ مَا شِئْتَ",
     "full_arabic": "عن أبي مسعود عقبة بن عمرو البدري رضي الله عنه قال: قال رسول الله صلى الله عليه وسلم: «إِنَّ مِمَّا أَدْرَكَ النَّاسُ مِنْ كَلَامِ النُّبُوَّةِ الْأُولَى: إِذَا لَمْ تَسْتَحِ فَاصْنَعْ مَا شِئْتَ»",
     "translation": "إن مما أدرك الناس من كلام النبوة الأولى: إذا لم تستح فاصنع ما شئت"},

    {"id": 21, "number": 21, "category": "الاستقامة", "narrator": "أبو عمرو سفيان بن عبد الله الثقفي رضي الله عنه", "source": "مسلم",
     "arabic": "قُلْ آمَنْتُ بِاللهِ، ثُمَّ اسْتَقِمْ",
     "full_arabic": "عن أبي عمرو سفيان بن عبد الله الثقفي رضي الله عنه قال: قلت: يا رسول الله، قل لي في الإسلام قولاً لا أسأل عنه أحداً غيرك. قال: «قُلْ آمَنْتُ بِاللهِ، ثُمَّ اسْتَقِمْ»",
     "translation": "قل آمنت بالله ثم استقم"},

    {"id": 22, "number": 22, "category": "الشريعة", "narrator": "جابر بن عبد الله الأنصاري رضي الله عنهما", "source": "مسلم",
     "arabic": "تُحْشَرُونَ يَوْمَ الْقِيَامَةِ عَلَى مَا مِتُّمْ عَلَيْهِ",
     "full_arabic": "عن جابر بن عبد الله الأنصاري رضي الله عنهما أن رسول الله صلى الله عليه وسلم قال: «تُحْشَرُونَ يَوْمَ الْقِيَامَةِ عَلَى مَا مِتُّمْ عَلَيْهِ»",
     "translation": "تحشرون يوم القيامة على ما متم عليه"},

    {"id": 23, "number": 23, "category": "النية", "narrator": "أبو مالك الحارث بن عاصم الأشعري رضي الله عنه", "source": "مسلم",
     "arabic": "الطُّهُورُ شَطْرُ الْإِيمَانِ، وَالْحَمْدُ لِلَّهِ تَمْلَأُ الْمِيزَانَ",
     "full_arabic": "عن أبي مالك الحارث بن عاصم الأشعري رضي الله عنه قال: قال رسول الله صلى الله عليه وسلم: «الطُّهُورُ شَطْرُ الْإِيمَانِ، وَالْحَمْدُ لِلَّهِ تَمْلَأُ الْمِيزَانَ، وَسُبْحَانَ اللهِ وَالْحَمْدُ لِلَّهِ تَمْلَآَنِ مَا بَيْنَ السَّمَاءِ وَالْأَرْضِ، وَالصَّلَاةُ نُورٌ، وَالصَّدَقَةُ بُرْهَانٌ، وَالصَّبْرُ ضِيَاءٌ، وَالْقُرْآنُ حُجَّةٌ لَكَ أَوْ عَلَيْكَ»",
     "translation": "الطهور شطر الإيمان، والحمد لله تملأ الميزان"},

    {"id": 24, "number": 24, "category": "تحريم البغي", "narrator": "أبو هريرة رضي الله عنه", "source": "مسلم",
     "arabic": "إِذَا قَاتَلَ أَحَدُكُمْ فَلْيَجْتَنِبِ الْوَجْهَ",
     "full_arabic": "عن أبي هريرة رضي الله عنه قال: قال رسول الله صلى الله عليه وسلم: «إِذَا قَاتَلَ أَحَدُكُمْ فَلْيَجْتَنِبِ الْوَجْهَ»",
     "translation": "إذا قاتل أحدكم فليجتنب الوجه"},

    {"id": 25, "number": 25, "category": "العدل", "narrator": "أبو ذر رضي الله عنه", "source": "متفق عليه",
     "arabic": "نِعْمَتَانِ مَغْبُونٌ فِيهِمَا كَثِيرٌ مِنَ النَّاسِ: الصِّحَّةُ وَالْفَرَاغُ",
     "full_arabic": "عن ابن عباس رضي الله عنهما قال: قال النبي صلى الله عليه وسلم: «نِعْمَتَانِ مَغْبُونٌ فِيهِمَا كَثِيرٌ مِنَ النَّاسِ: الصِّحَّةُ وَالْفَرَاغُ»",
     "translation": "نعمتان مغبون فيهما كثير من الناس: الصحة والفراغ"},

    {"id": 26, "number": 26, "category": "الصدقة", "narrator": "أبو هريرة رضي الله عنه", "source": "مسلم",
     "arabic": "كُلُّ سُلَامَى مِنَ النَّاسِ عَلَيْهِ صَدَقَةٌ، كُلَّ يَوْمٍ تَطْلُعُ فِيهِ الشَّمْسُ",
     "full_arabic": "عن أبي هريرة رضي الله عنه قال: قال رسول الله صلى الله عليه وسلم: «كُلُّ سُلَامَى مِنَ النَّاسِ عَلَيْهِ صَدَقَةٌ، كُلَّ يَوْمٍ تَطْلُعُ فِيهِ الشَّمْسُ: تَعْدِلُ بَيْنَ اثْنَيْنِ صَدَقَةٌ، وَتُعِينُ الرَّجُلَ فِي دَابَّتِهِ فَتَحْمِلُ عَلَيْهَا أَوْ تَرْفَعُ لَهُ عَلَيْهَا مَتَاعَهُ صَدَقَةٌ»",
     "translation": "كل سلامى من الناس عليه صدقة، كل يوم تطلع فيه الشمس"},

    {"id": 27, "number": 27, "category": "البر", "narrator": "النواس بن سمعان رضي الله عنه", "source": "مسلم",
     "arabic": "الْبِرُّ حُسْنُ الْخُلُقِ، وَالْإِثْمُ مَا حَاكَ فِي نَفْسِكَ وَكَرِهْتَ أَنْ يَطَّلِعَ عَلَيْهِ النَّاسُ",
     "full_arabic": "عن النواس بن سمعان رضي الله عنه عن النبي صلى الله عليه وسلم قال: «الْبِرُّ حُسْنُ الْخُلُقِ، وَالْإِثْمُ مَا حَاكَ فِي نَفْسِكَ وَكَرِهْتَ أَنْ يَطَّلِعَ عَلَيْهِ النَّاسُ»",
     "translation": "البر حسن الخلق، والإثم ما حاك في نفسك وكرهت أن يطلع عليه الناس"},

    {"id": 28, "number": 28, "category": "الوصية", "narrator": "وَبِيصَةَ بن معبد رضي الله عنه", "source": "أحمد والدارمي",
     "arabic": "اسْتَفْتِ قَلْبَكَ: الْبِرُّ مَا اطْمَأَنَّتْ إِلَيْهِ النَّفْسُ وَاطْمَأَنَّ إِلَيْهِ الْقَلْبُ",
     "full_arabic": "عن وابصة بن معبد رضي الله عنه قال: أتيت رسول الله صلى الله عليه وسلم فقال: «جِئْتَ تَسْأَلُ عَنِ الْبِرِّ؟». قلت: نعم. فقال: «اسْتَفْتِ قَلْبَكَ: الْبِرُّ مَا اطْمَأَنَّتْ إِلَيْهِ النَّفْسُ وَاطْمَأَنَّ إِلَيْهِ الْقَلْبُ، وَالْإِثْمُ مَا حَاكَ فِي النَّفْسِ وَتَرَدَّدَ فِي الصَّدْرِ وَإِنْ أَفْتَاكَ النَّاسُ وَأَفْتَوْكَ»",
     "translation": "استفت قلبك: البر ما اطمأنت إليه النفس واطمأن إليه القلب"},

    {"id": 29, "number": 29, "category": "حفظ اللسان", "narrator": "معاذ بن جبل رضي الله عنه", "source": "الترمذي",
     "arabic": "أَلَا أُخْبِرُكَ بِمَلَاكِ ذَلِكَ كُلِّهِ؟ قُلْتُ: بَلَى يَا نَبِيَّ اللهِ. فَأَخَذَ بِلِسَانِهِ قَالَ: كُفَّ عَلَيْكَ هَذَا",
     "full_arabic": "عن معاذ بن جبل رضي الله عنه قال: قلت: يا رسول الله، أخبرني بعمل يدخلني الجنة ويباعدني عن النار. قال: «لَقَدْ سَأَلْتَ عَنْ عَظِيمٍ، وَإِنَّهُ لَيَسِيرٌ عَلَى مَنْ يَسَّرَهُ اللهُ عَلَيْهِ...» ثم قال: «أَلَا أُخْبِرُكَ بِمَلَاكِ ذَلِكَ كُلِّهِ؟». قُلْتُ: بَلَى يَا نَبِيَّ اللهِ. فَأَخَذَ بِلِسَانِهِ قَالَ: «كُفَّ عَلَيْكَ هَذَا»",
     "translation": "ألا أخبرك بملاك ذلك كله؟ كف عليك هذا"},

    {"id": 30, "number": 30, "category": "حق الجار", "narrator": "ابن مسعود رضي الله عنه", "source": "متفق عليه",
     "arabic": "وَاللهِ لَا يُؤْمِنُ، وَاللهِ لَا يُؤْمِنُ، وَاللهِ لَا يُؤْمِنُ. قِيلَ: مَنْ يَا رَسُولَ اللهِ؟ قَالَ: الَّذِي لَا يَأْمَنُ جَارُهُ بَوَائِقَهُ",
     "full_arabic": "عن عبد الله بن مسعود رضي الله عنه قال: قال رسول الله صلى الله عليه وسلم: «وَاللهِ لَا يُؤْمِنُ، وَاللهِ لَا يُؤْمِنُ، وَاللهِ لَا يُؤْمِنُ». قِيلَ: مَنْ يَا رَسُولَ اللهِ؟ قَالَ: «الَّذِي لَا يَأْمَنُ جَارُهُ بَوَائِقَهُ»",
     "translation": "والله لا يؤمن، والله لا يؤمن، والله لا يؤمن، قيل: من يا رسول الله؟ قال: الذي لا يأمن جاره بوائقه"},

    {"id": 31, "number": 31, "category": "الزهد", "narrator": "أبو العباس سهل بن سعد الساعدي رضي الله عنه", "source": "البخاري",
     "arabic": "مَنْ يَتَوَكَّلْ عَلَى اللهِ يَكْفِهِ",
     "full_arabic": "عن أبي العباس سهل بن سعد الساعدي رضي الله عنه قال: جاء رجل إلى النبي صلى الله عليه وسلم فقال: يا رسول الله، دلني على عمل إذا عملته أحبني الله وأحبني الناس. فقال: «ازْهَدْ فِي الدُّنْيَا يُحِبَّكَ اللهُ، وَازْهَدْ فِيمَا فِي أَيْدِي النَّاسِ يُحِبُّوكَ»",
     "translation": "ازهد في الدنيا يحبك الله، وازهد فيما في أيدي الناس يحبوك"},

    {"id": 32, "number": 32, "category": "الكمال", "narrator": "أبو سعيد الخدري رضي الله عنه", "source": "البخاري",
     "arabic": "لَا ضَرَرَ وَلَا ضِرَارَ",
     "full_arabic": "عن أبي سعيد الخدري رضي الله عنه أن رسول الله صلى الله عليه وسلم قال: «لَا ضَرَرَ وَلَا ضِرَارَ»",
     "translation": "لا ضرر ولا ضرار"},

    {"id": 33, "number": 33, "category": "الأمر بالمعروف", "narrator": "ابن عباس رضي الله عنهما", "source": "البخاري",
     "arabic": "لَوْ يُعْطَى النَّاسُ بِدَعْوَاهُمْ لَادَّعَى نَاسٌ دِمَاءَ رِجَالٍ وَأَمْوَالَهُمْ، وَلَكِنَّ الْبَيِّنَةَ عَلَى الْمُدَّعِي وَالْيَمِينَ عَلَى مَنْ أَنْكَرَ",
     "full_arabic": "عن ابن عباس رضي الله عنهما أن رسول الله صلى الله عليه وسلم قال: «لَوْ يُعْطَى النَّاسُ بِدَعْوَاهُمْ لَادَّعَى نَاسٌ دِمَاءَ رِجَالٍ وَأَمْوَالَهُمْ، وَلَكِنَّ الْبَيِّنَةَ عَلَى الْمُدَّعِي وَالْيَمِينَ عَلَى مَنْ أَنْكَرَ»",
     "translation": "لو يعطى الناس بدعواهم لادعى ناس دماء رجال وأموالهم، لكن البينة على المدعي واليمين على من أنكر"},

    {"id": 34, "number": 34, "category": "التيسير", "narrator": "أبو سعيد الخدري رضي الله عنه", "source": "مسلم",
     "arabic": "مَنْ رَأَى مِنْكُمْ مُنْكَرًا فَلْيُغَيِّرْهُ بِيَدِهِ، فَإِنْ لَمْ يَسْتَطِعْ فَبِلِسَانِهِ، فَإِنْ لَمْ يَسْتَطِعْ فَبِقَلْبِهِ، وَذَلِكَ أَضْعَفُ الْإِيمَانِ",
     "full_arabic": "عن أبي سعيد الخدري رضي الله عنه قال: سمعت رسول الله صلى الله عليه وسلم يقول: «مَنْ رَأَى مِنْكُمْ مُنْكَرًا فَلْيُغَيِّرْهُ بِيَدِهِ، فَإِنْ لَمْ يَسْتَطِعْ فَبِلِسَانِهِ، فَإِنْ لَمْ يَسْتَطِعْ فَبِقَلْبِهِ، وَذَلِكَ أَضْعَفُ الْإِيمَانِ»",
     "translation": "من رأى منكم منكراً فليغيره بيده، فإن لم يستطع فبلسانه، فإن لم يستطع فبقلبه"},

